#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e2+5,PowN=1e4+5;
int n,m,ans=0,dis[MAXN][MAXN],a[PowN];
void Floyd(){
	for(int k=1;k<=n;++k)
		for(int i=1;i<=n;++i)
			for(int j=1;j<=n;++j)
				dis[i][j]=min(dis[i][k]+dis[k][j],dis[i][j]);
}int main(void){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;++i)scanf("%d",a+i);
	for(int i=1;i<=n;++i)
		for(int j=1;j<=n;++j)scanf("%d",&dis[i][j]);
	Floyd();
	for(int i=2;i<=m;++i)ans+=dis[a[i-1]][a[i]];
	printf("%d",ans);
	return false;
}
